/* ═══════════════════════════════════════════════════════════════════
 *  BUDDY SYSTEM — password-gated, AES-GCM encrypted (MoECON)
 *
 *  Same pattern as Battle Orders: the full Buddy System tool (CSS,
 *  HTML, JS) is encrypted in BUDDY_ENCRYPTED_PAYLOAD below.
 *
 *  Blob format: base64 of  salt(16) || iv(12) || AES-GCM-256 ciphertext
 *  Key derivation:         PBKDF2-SHA-256, 200000 iterations
 *
 *  To set up or rotate the password: encrypt buddy-payload.js with
 *  encrypt-bo.html (the encryptor is payload-agnostic) and paste the
 *  resulting base64 string as the value of BUDDY_ENCRYPTED_PAYLOAD.
 *
 *  Until BUDDY_ENCRYPTED_PAYLOAD is set, the gate shows
 *  "Buddy System payload not configured yet." and the tool doesn't load.
 * ═══════════════════════════════════════════════════════════════════ */
const BuddySystemGate = (() => {
  // PASTE YOUR ENCRYPTED BLOB HERE (single line, base64, no surrounding quotes).
  const BUDDY_ENCRYPTED_PAYLOAD = '';

  const $gate      = document.getElementById('buddy-gate');
  const $gateForm  = document.getElementById('buddy-gate-form');
  const $gatePw    = document.getElementById('buddy-gate-pw');
  const $gateError = document.getElementById('buddy-gate-error');
  const $gateBtn   = document.getElementById('buddy-gate-submit');

  let unlocked = false;
  let injected = false;

  async function deriveKey(password, salt) {
    const enc = new TextEncoder();
    const keyMaterial = await crypto.subtle.importKey(
      'raw', enc.encode(password), 'PBKDF2', false, ['deriveKey']
    );
    return crypto.subtle.deriveKey(
      { name: 'PBKDF2', salt, iterations: 200000, hash: 'SHA-256' },
      keyMaterial,
      { name: 'AES-GCM', length: 256 },
      false, ['decrypt']
    );
  }

  async function decryptPayload(password) {
    if (!BUDDY_ENCRYPTED_PAYLOAD) throw new Error('NOT_CONFIGURED');
    const bytes = Uint8Array.from(atob(BUDDY_ENCRYPTED_PAYLOAD), c => c.charCodeAt(0));
    if (bytes.length < 28) throw new Error('Malformed payload.');
    const salt = bytes.slice(0, 16);
    const iv   = bytes.slice(16, 28);
    const ct   = bytes.slice(28);
    const key  = await deriveKey(password, salt);
    const plain = await crypto.subtle.decrypt({ name: 'AES-GCM', iv }, key, ct);
    return new TextDecoder().decode(plain);
  }

  function injectAndRun(code) {
    if (injected) return;
    injected = true;
    const s = document.createElement('script');
    s.textContent = code;
    document.body.appendChild(s);
  }

  async function tryUnlock(password) {
    $gateBtn.disabled = true;
    $gateError.textContent = '';
    try {
      const code = await decryptPayload(password);
      $gate.style.display = 'none';
      unlocked = true;
      injectAndRun(code);
    } catch (e) {
      $gateError.textContent = e.message === 'NOT_CONFIGURED'
        ? 'Buddy System payload not configured yet.'
        : 'Incorrect password.';
      $gatePw.select();
    } finally {
      $gateBtn.disabled = false;
    }
  }

  $gateForm.addEventListener('submit', e => {
    e.preventDefault();
    const pw = $gatePw.value;
    if (pw) tryUnlock(pw);
  });

  return {
    activate() {
      if (unlocked) return;          // Already in; DOM persists across nav.
      $gate.style.display = '';
      $gatePw.value = '';
      $gateError.textContent = '';
      setTimeout(() => $gatePw.focus(), 50);
    }
  };
})();